class FileSystem:
    def __init__(self):
        self.root = {"dirs": {}, "files": {}}
    def ls(self, path):
        node = self.root
        if path != "/":
            for p in path.split("/")[1:]:
                if p in node["dirs"]: node = node["dirs"][p]
                else: return [p]
        return sorted(list(node["dirs"].keys()) + list(node["files"].keys()))
    def mkdir(self, path):
        node = self.root
        for p in path.split("/")[1:]:
            node = node["dirs"].setdefault(p, {"dirs": {}, "files": {}})
    def addContentToFile(self, filePath, content):
        parts = filePath.split("/"); node = self.root
        for p in parts[1:-1]: node = node["dirs"][p]
        node["files"][parts[-1]] = node["files"].get(parts[-1], "") + content
    def readContentFromFile(self, filePath):
        parts = filePath.split("/"); node = self.root
        for p in parts[1:-1]: node = node["dirs"][p]
        return node["files"][parts[-1]]

